import { merge } from '@adobe-commerce/elsie/lib';
import {
  RecommendationUnitModel,
  PageType,
  Item,
} from '@/recommendations/data/models';
import { config } from '@/recommendations/api';

export function transformRecommendations(
  data: any,
  recId?: string
): RecommendationUnitModel[] {
  if (!data || !data.results?.length) return [];

  // Filter out any results that don't have a matching recId if recId is provided
  const resultsToTransform = recId
    ? data.results.filter((result: any) => result.unitId === recId)
    : data.results;

  // Warn if recId doesn't match any recommendation units
  if (recId && resultsToTransform.length === 0) {
    console.warn(
      `ProductList: recId "${recId}" does not match any recommendation units. Available unitIds: ${data.results
        .map((result: any) => result.unitId)
        .join(', ')}`
    );
  }

  const model = resultsToTransform.map(
    (result: any): RecommendationUnitModel => ({
      displayOrder: result.displayOrder ?? 0,
      pageType: result.pageType as PageType,
      title: result.storefrontLabel ?? '',
      items: transformItems(result.productsView ?? []),
      totalProducts: result.totalProducts ?? 0,
      typeId: result.typeId ?? '',
      unitId: result.unitId ?? '',
      unitName: result.unitName ?? '',
      userError: result.userError ?? '',
    })
  );

  // extend the model with custom transformer
  return merge(
    model,
    config.getConfig().models?.RecommendationUnitModel?.transformer?.(data)
  );
}

function transformItems(products: any): Item[] {
  if (!products?.length) return [];

  return products.map((product: any) => ({
    itemType: product.__typename ?? '',
    uid: product.sku,
    sku: product.sku,
    name: product.name ?? '',
    urlKey: product.urlKey ?? '',
    images: [
      {
        label: product.name ?? '',
        roles: ['thumbnail'],
        url: (product.images?.[0]?.url ?? '').replace('http://', '//'),
      },
    ],
    price: {
      final: {
        amount: {
          value: product.price?.final?.amount?.value,
          currency: product.price?.final?.amount?.currency,
        },
      },
    },
    priceRange: {
      minimum: {
        final: {
          amount: {
            value: product.priceRange?.minimum?.final?.amount?.value,
            currency: product.priceRange?.minimum?.final?.amount?.currency,
          },
        },
      },
      maximum: {
        final: {
          amount: {
            value: product.priceRange?.maximum?.final?.amount?.value,
            currency: product.priceRange?.maximum?.final?.amount?.currency,
          },
        },
      },
    },
    visibility: product.visibility ?? '',
    queryType: product.queryType ?? '',
    inStock: product.inStock ?? true,
  }));
}
