import { RecommendationUnit, RecommendedProduct } from '../models/acdl-models';
import { Item, RecommendationUnitModel } from '@/recommendations/data/models';

/**
 * Transform a recommendation unit data object into an ACDL model
 *
 * @param unitData - The recommendation unit data object to transform
 * @param additionalData - Additional data that may not be present in the unit data object
 * @returns The transformed recommendation unit
 */
export const transformRecommendationUnit = (
  unitData: RecommendationUnitModel,
  additionalData?: any
) => {
  // Handle null or undefined unitData
  if (!unitData) {
    console.error('transformRecommendationUnit: unitData is null or undefined');
    throw new Error(
      'Recommendation unit data is required but was not provided'
    );
  }

  // Ensure items exists and is an array
  const items = unitData.items || [];

  const recUnit: RecommendationUnit = {
    unitId: unitData.unitId,
    unitName: unitData.unitName,
    typeId: unitData.typeId,
    unitType: unitData.typeId, // This is an assumption that the unit type is the typeId since the GraphQL schema does not have a unitType field
    totalProducts: unitData.totalProducts,
    primaryProducts: items.length, // This is an assumption that the primary products are the total items in the unit
    products: items.map((item, index) =>
      transformRecommendationProduct(item, index)
    ),
    // Data that may not be present in the unit data object
    searchTime: additionalData?.searchTime || 0,
    backupProducts: additionalData?.backupProducts || 0,
    pagePlacement: additionalData?.pagePlacement || '',
    yOffsetTop: additionalData?.yOffsetTop || null,
    yOffsetBottom: additionalData?.yOffsetBottom || null,
  };

  return recUnit;
};

/**
 * Transform a product view data object into an ACDL model
 *
 * @param productData - The product view data object to transform
 * @param index - The index of the product in the recommendation unit
 * @returns The transformed product
 */
const transformRecommendationProduct = (
  productData: Item,
  index: number = 0
) => {
  const recProduct: RecommendedProduct = {
    productId: Number(index), // Ensure productId is a number. This is an assumption that the product id is the index
    sku: productData.sku,
    name: productData.name,
    url: productData.urlKey,
    visibility: productData.visibility,
    queryType: productData.queryType,

    rank: Number(index), // Ensure rank is a number
    type: productData.itemType, // Using itemType from the model

    score: 0, // Deprecated in the GraphQL schema but is required by the ACDL model
    categories: [], // Deprecated in the GraphQL schema but is required by the ACDL model

    weight: 0, // Not sure where this is coming from its not in the GraphQL schema

    // Optional fields that have corresponding fields in the GraphQL schema
    image: productData.images?.[0],
  };

  return recProduct;
};
