import { transformRecommendationUnit } from '@/recommendations/data/transforms/acdl-context';
import { pushEvent, setContext } from '@/recommendations/lib/acdl/utils';
import { RECOMMENDATIONS_CONTEXT } from '@/recommendations/lib/acdl/contexts';
import { RECS_ITEM_ADD_TO_CART_CLICK } from '@/recommendations/lib/acdl/events';
import { Recommendations } from '@/recommendations/data/models/acdl-models';

/**
 * Parameters for the publish events
 *
 * item: The item that was added to the cart
 * pagePlacement: The placement of the item on the page
 * yOffsetTop: The y offset of the item from the top of the page
 * yOffsetBottom: The y offset of the item from the bottom of the page
 */
export interface PublishParams {
  recommendationUnit: any; // TODO: Replace this with the actual RecommendationMdoel type when PR #7 is merged
  pagePlacement: string;
  yOffsetTop: number;
  yOffsetBottom: number;
  backupProducts?: number;
  searchTime?: number;
  productId?: number; // The index of the clicked product
}

/**
 * Publish a recs-item-add-to-cart-click event to the Adobe Client Data Layer (ACDL)
 *
 * See: https://experienceleague.adobe.com/en/docs/commerce/product-recommendations/developer/events#events
 * @param params - The parameters for the event
 */
export const publishRecsItemAddToCartClick = (params: PublishParams) => {
  const { productId, recommendationUnit, ...additionalData } = params;

  const recommendationUnitContext = transformRecommendationUnit(
    recommendationUnit,
    additionalData
  );

  setContext<Recommendations>(RECOMMENDATIONS_CONTEXT, {
    units: [recommendationUnitContext],
  });

  pushEvent(RECS_ITEM_ADD_TO_CART_CLICK, undefined, {
    unitId: recommendationUnitContext.unitId,
    productId,
  });
};
