import { fetchGraphQl } from '@/recommendations/api/fetch-graphql';
import { handleFetchError } from '@/recommendations/lib/fetch-error';
import {
    GET_RECOMMENDATIONS_BY_UNIT_IDS_QUERY,
    GET_RECOMMENDATIONS_BY_UNIT_IDS_WITH_PRODUCT_QUERY,
} from '@/recommendations/api/getRecommendationsByUnitIds/graphql/GetRecommendationsByUnitIdsQuery';
import {
    GraphQLResponse,
    RecommendationUnitModel,
} from '@/recommendations/data/models';
import { events } from '@adobe-commerce/event-bus';
import { transformRecommendations } from '@/recommendations/data/transforms';
import {
    publishRecsApiRequestSent,
    publishRecsApiResponseReceived,
} from '@/recommendations/lib/acdl/publish';

export interface CurrentProduct {
    sku?: string;
    price?: number;
}

export interface GetRecommendationsByUnitIdsProps {
    currentSku?: string;
    cartSkus?: string[];
    userPurchaseHistory?: any[];
    userViewHistory?: any[];
    unitIds: string[];
    currentProduct?: CurrentProduct;
}

export const getRecommendationsByUnitIds = async (
    params: GetRecommendationsByUnitIdsProps
): Promise<RecommendationUnitModel[] | null> => {
    // Publish recs-api-request-sent event before making the API request
    publishRecsApiRequestSent();

    // Use the extended query only when currentProduct carries a price.
    // SKU-only currentProduct falls through to the base query via currentSku,
    // keeping PaaS backends (which lack CurrentProductInput) compatible.
    const { currentProduct, ...baseVariables } = params;
    const hasCurrentProduct = currentProduct?.price != null;
    const query = hasCurrentProduct
        ? GET_RECOMMENDATIONS_BY_UNIT_IDS_WITH_PRODUCT_QUERY
        : GET_RECOMMENDATIONS_BY_UNIT_IDS_QUERY;
    const variables = hasCurrentProduct
        ? params
        : baseVariables;

    return fetchGraphQl(query, {
        method: 'GET',
        variables,
    }).then(({ errors, data }: GraphQLResponse) => {
        if (errors && errors.length > 0) return handleFetchError(errors);

        // transform recommendations
        const payload = transformRecommendations(
            data?.recommendationsByUnitIds,
        );

        // Publish recs-api-response-received event for each recommendation unit
        if (payload && payload.length > 0) {
            payload.forEach((unit) => {
                publishRecsApiResponseReceived({
                    recommendationUnit: unit,
                    pagePlacement: 'api-response',
                    yOffsetTop: 0,
                    yOffsetBottom: 0,
                    backupProducts: 0,
                    searchTime: 0,
                });
            });
        }

        // emit events
        events.emit('recommendations/data', payload);

        return payload;
    });
};
